import 'package:flutter/material.dart';

// 1. 定义一个ValueNotifier，泛型为状态数据的类型（这里是int）
final ValueNotifier<int> _counterNotifier = ValueNotifier<int>(0);
// 另外定义一个颜色状态，演示多个独立状态
final ValueNotifier<Color> _colorNotifier = ValueNotifier<Color>(Colors.blue);

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'ValueNotifier Demo',
      home: Scaffold(
        appBar: AppBar(title: const Text('ValueNotifier高效状态管理')),
        body: Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              // 2. 使用ValueListenableBuilder来监听特定的ValueNotifier
              // 只有当_counterNotifier.value变化时，这个Builder才会重建
              ValueListenableBuilder<int>(
                valueListenable: _counterNotifier,
                builder: (context, value, child) {
                  debugPrint('Counter Widget Rebuilt!'); // 验证重建范围
                  return Text(
                    '计数: $value',
                    style: const TextStyle(fontSize: 30),
                  );
                },
              ),
              const SizedBox(height: 20),
              // 3. 监听另一个独立的状态：颜色
              ValueListenableBuilder<Color>(
                valueListenable: _colorNotifier,
                builder: (context, color, child) {
                  debugPrint('Color Widget Rebuilt!');
                  return Container(
                    width: 100,
                    height: 100,
                    color: color,
                    child: const Center(child: Text('变化区域')),
                  );
                },
              ),
              const SizedBox(height: 30),
              // 4. 按钮：修改ValueNotifier的值
              Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  ElevatedButton(
                    onPressed: () {
                      // 通过.value属性修改值，这会自动触发通知
                      _counterNotifier.value++;
                      _colorNotifier.value =
                          _counterNotifier.value % 2 == 0 ? Colors.blue : Colors.red;
                    },
                    child: const Text('修改计数和颜色'),
                  ),
                  const SizedBox(width: 20),
                  ElevatedButton(
                    onPressed: () {
                      // 重置状态
                      _counterNotifier.value = 0;
                      _colorNotifier.value = Colors.blue;
                    },
                    child: const Text('重置'),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

